// SellerDetails.jsx

// SellerDetails.jsx
import React, { useState, useEffect } from 'react';
//import axios from 'axios';
import { useParams } from 'react-router-dom';

const SellerDetails = () => {
  const [seller, setSeller] = useState(null);
  const id = "e53d209c-0e1d-4b6e-a670-96aa2d2ad94b";

  useEffect(() => {
    const fetchSeller = async () => {
      try {
       // const response = await axios.get(`/seller/getSeller/${sellerId}`);
       const response = await fetch(`http://localhost:5000/seller/getSeller/${id}`);
    // const response = await fetch("http://localhost:5000/seller/getSeller/e53d209c-0e1d-4b6e-a670-96aa2d2ad94b");
       if (!response.ok) {
        throw new Error("Failed to fetch seller");
      }
       const jsonData = await response.json();
       console.log(jsonData);
        setSeller(jsonData);
      } catch (error) {
        console.error(error.message);
      }
    };

    fetchSeller();
  }, [id]);

  if (!seller) return <div>Loading...</div>;

  return (
    <div>
      <h2>Seller Details</h2>
      <p>TIN: {seller.tin}</p>
      <p>Website: {seller.website}</p>
      <p>Factory Address: {seller.factory_address}</p>
      <p>Office Address: {seller.office_address}</p>
    </div>
  );
};

export default SellerDetails;
